    """
    Predict the next frame for the 64x64 grid game.

    The game contains four fixed 4×8 blocks that are toggled by the
    actions ACTION1..ACTION4.  The block positions are:

        ACTION1 → (44, 36)
        ACTION2 → ( 4, 16)
        ACTION3 → (48, 36)
        ACTION4 → (52,  4)

    Inside a block the following value transitions occur:

        ACTION1: 1 → 0   (left half), 0 → 1   (right half)
        ACTION2: 14 → 1  (left half), 1 → 0   (right half)
        ACTION3: 1  → 0  (left half), 0 → 1   (right half)
        ACTION4: 14 → 1  (left half), 1 → 0   (right half)

    All other cells remain unchanged.
    """
    # Deep copy to avoid mutating the input
    new_frame = [row[:] for row in frame]

    # Mapping from action to block top‑left corner
    block_start = {
        "ACTION1": (44, 36),
        "ACTION2": (4, 16),
        "ACTION3": (48, 36),
        "ACTION4": (52, 4),
    }

    if action not in block_start:
        return new_frame  # No change for other actions

    r0, c0 = block_start[action]

    for dr in range(4):
        for dc in range(8):
            r, c = r0 + dr, c0 + dc
            if 0 <= r < 64 and 0 <= c < 64:
                val = new_frame[r][c]
                # Determine which half of the block we are in
                left_half = dc < 4
                if action in ("ACTION1", "ACTION3"):
                    if left_half:
                        if val == 1:
                            new_frame[r][c] = 0
                    else:
                        if val == 0:
                            new_frame[r][c] = 1
                else:  # ACTION2 or ACTION4
                    if left_half:
                        if val == 14:
                            new_frame[r][c] = 1
                    else:
                        if val == 1:
                            new_frame[r][c] = 0
    return new_frame

